const items = $input.all();

const paramKeys = ['btag', 'stag', 'cxd', 'mid', 'affid'];

return items.map(item => {
  const finalUrl = item.json.final_url || '';
  let sTag = '';
  let siteName = '';

  try {
    // Extract site name manually
    const withoutProtocol = finalUrl.replace(/^https?:\/\//, '');
    const hostname = withoutProtocol.split('/')[0].replace(/^www\./, '');
    siteName = hostname.split('.')[0];

    // Parse query string manually
    const rawQuery = finalUrl.split('?')[1] || '';
    const params = {};

    rawQuery.split('&').forEach(pair => {
      const eqIndex = pair.indexOf('=');
      if (eqIndex > -1) {
        const key = pair.substring(0, eqIndex);
        const value = pair.substring(eqIndex + 1);
        params[key] = value;
      }
    });

    for (const key of paramKeys) {
      if (params[key]) {
        sTag = params[key].split('_')[0];
        break;
      }
    }
  } catch (e) {
    // stays empty
  }

  return {
    json: {
      ...item.json,
      s_tag: sTag,
      site_name: siteName,
      source_id: $('Loop Over Items').first().json.source_id
    }
  };
});

const MAX_LINKS = 10;

const input = $input.first().json;
const { linksToExtract, source_id, country } = input;

// Parse the stringified JSON into an actual array
const parsedLinks = JSON.parse(linksToExtract);

// Now you can safely slice and map the array
return parsedLinks.slice(0, MAX_LINKS).map(link => ({
  json: { ...link, source_id, country }
}));

const staticData = $getWorkflowStaticData('global');

// Initialize on first iteration
if (!staticData.sTagsHolder) {
  staticData.sTagsHolder = [];
}

// Get current item from the previous node
const currentItem = $input.item.json;

// Append to array — replace these fields with your actual keys
staticData.sTagsHolder.push({
  s_tag: currentItem.s_tag,
  site_name: currentItem.site_name,
  source_id: $input.first().json.source_id
});

// Pass the item through so the loop can continue
return [{ json: currentItem }];

const staticData = $getWorkflowStaticData('global');

// Grab the final accumulated array
const finalArray = staticData.sTagsHolder || [];

// Clear it so the next execution starts fresh
staticData.sTagsHolder = null;

// Group by s_tag
const tagMap = {};

for (const item of finalArray) {
  if (!item.s_tag) continue;

  if (!tagMap[item.s_tag]) {
    tagMap[item.s_tag] = {
      s_tag: item.s_tag,
      site_names: new Set(),
      source_id: item.source_id
    };
  }

  if (item.site_name) {
    tagMap[item.s_tag].site_names.add(item.site_name);
  }
}

// Convert to final array
const deduped = Object.values(tagMap).map(entry => ({
  s_tag: entry.s_tag,
  site_name: Array.from(entry.site_names).join(', '),
  source_id: entry.source_id
}));

return [{ json: { sTagsHolder: deduped } }];
